const courses = $input.first().json.courses || [];
// Only return active courses
return courses
  .filter(c => c.courseState === 'ACTIVE')
  .map(course => ({
    json: {
      courseId: course.id,
      courseName: course.name,
      courseSection: course.section || ''
    }
  }));

// Merge assignments with submission statuses
const courseWork = $('Get Course Assignments').first().json.courseWork || [];
const submissions = $('Get My Submissions').first().json.studentSubmissions || [];
const courseInfo = $('Loop Courses').first().json;

// Build submission map: courseWorkId -> state
const submissionMap = {};
for (const sub of submissions) {
  submissionMap[sub.courseWorkId] = {
    state: sub.state,
    late: sub.late || false,
    assignedGrade: sub.assignedGrade || null,
    draftGrade: sub.draftGrade || null
  };
}

const now = new Date();

const tasks = courseWork.map(work => {
  const sub = submissionMap[work.id] || {};

  // Build due date
  let dueDate = null;
  let daysUntilDue = null;
  let urgency = 'none';

  if (work.dueDate) {
    const d = work.dueDate;
    const t = work.dueTime || { hours: 23, minutes: 59 };
    dueDate = new Date(d.year, d.month - 1, d.day, t.hours || 23, t.minutes || 59);
    daysUntilDue = Math.ceil((dueDate - now) / (1000 * 60 * 60 * 24));

    if (daysUntilDue < 0) urgency = 'overdue';
    else if (daysUntilDue <= 1) urgency = 'critical';
    else if (daysUntilDue <= 3) urgency = 'high';
    else if (daysUntilDue <= 7) urgency = 'medium';
    else urgency = 'low';
  }

  // Submission state mapping
  const stateMap = {
    'TURNED_IN': '✅ Submitted',
    'RETURNED': '📬 Returned',
    'CREATED': '📝 Not started',
    'RECLAIMED_BY_STUDENT': '↩️ Reclaimed'
  };

  return {
    courseId: courseInfo.courseId,
    courseName: courseInfo.courseName,
    workId: work.id,
    title: work.title,
    description: (work.description || '').slice(0, 200),
    workType: work.workType,
    maxPoints: work.maxPoints || null,
    dueDate: dueDate ? dueDate.toISOString() : null,
    dueDateFormatted: dueDate ? dueDate.toLocaleDateString('en-AU', { weekday: 'short', day: 'numeric', month: 'short', year: 'numeric' }) : 'No due date',
    daysUntilDue: daysUntilDue,
    urgency: urgency,
    submissionState: stateMap[sub.state] || '❓ Unknown',
    rawState: sub.state || 'UNKNOWN',
    isLate: sub.late || false,
    grade: sub.assignedGrade || sub.draftGrade || null,
    isComplete: ['TURNED_IN', 'RETURNED'].includes(sub.state)
  };
});

// Sort by urgency then due date
const urgencyOrder = { overdue: 0, critical: 1, high: 2, medium: 3, low: 4, none: 5 };
tasks.sort((a, b) => {
  const uDiff = (urgencyOrder[a.urgency] || 5) - (urgencyOrder[b.urgency] || 5);
  if (uDiff !== 0) return uDiff;
  if (a.dueDate && b.dueDate) return new Date(a.dueDate) - new Date(b.dueDate);
  return 0;
});

return tasks.map(t => ({ json: t }));

// Aggregate all tasks and generate Obsidian markdown
const allTasks = $input.all().map(i => i.json);
const now = new Date();
const dateStr = now.toISOString().split('T')[0];
const ts = now.toISOString().replace('T', ' ').slice(0, 16);

// Group by course
const byCourse = {};
for (const task of allTasks) {
  if (!byCourse[task.courseName]) byCourse[task.courseName] = [];
  byCourse[task.courseName].push(task);
}

// Urgency emoji
const urgencyEmoji = {
  overdue: '🔴',
  critical: '🟠',
  high: '🟡',
  medium: '🔵',
  low: '🟢',
  none: '⚪'
};

// Build pending tasks section
const pendingTasks = allTasks.filter(t => !t.isComplete && t.dueDate);
const completedTasks = allTasks.filter(t => t.isComplete);

let pendingSection = '';
for (const task of pendingTasks) {
  const emoji = urgencyEmoji[task.urgency] || '⚪';
  const dueInfo = task.daysUntilDue !== null
    ? (task.daysUntilDue < 0 ? `⚠️ ${Math.abs(task.daysUntilDue)}d overdue` : `${task.daysUntilDue}d left`)
    : 'No due date';
  pendingSection += `- [ ] ${emoji} **${task.title}** | ${task.courseName} | 📅 ${task.dueDateFormatted} (${dueInfo}) | ${task.submissionState}\n`;
}

// Build by-course section
let courseSections = '';
for (const [course, tasks] of Object.entries(byCourse)) {
  courseSections += `\n### ${course}\n\n`;
  for (const task of tasks) {
    const emoji = urgencyEmoji[task.urgency] || '⚪';
    const checkbox = task.isComplete ? '[x]' : '[ ]';
    const gradeStr = task.grade !== null ? ` | Grade: ${task.grade}/${task.maxPoints}` : '';
    courseSections += `- ${checkbox} ${emoji} **${task.title}**\n`;
    courseSections += `  - Due: ${task.dueDateFormatted}\n`;
    courseSections += `  - Status: ${task.submissionState}${gradeStr}\n`;
    if (task.description) courseSections += `  - ${task.description.slice(0, 100)}${task.description.length > 100 ? '...' : ''}\n`;
    courseSections += `\n`;
  }
}

// Stats
const total = allTasks.length;
const complete = completedTasks.length;
const overdue = allTasks.filter(t => t.urgency === 'overdue' && !t.isComplete).length;
const dueThisWeek = allTasks.filter(t => t.daysUntilDue !== null && t.daysUntilDue <= 7 && t.daysUntilDue >= 0 && !t.isComplete).length;

const markdown = `---
type: task-tracker
date: ${dateStr}
last_updated: "${ts}"
tags: [tasks, tracker, assignments]
---

# 📋 Assignment Tracker

> Last updated: ${ts}

## 📊 Summary

| Metric | Count |
|--------|-------|
| Total Assignments | ${total} |
| Completed | ${complete} |
| Pending | ${total - complete} |
| Overdue | ${overdue} |
| Due This Week | ${dueThisWeek} |
| Completion Rate | ${total > 0 ? Math.round((complete / total) * 100) : 0}% |

## 🚨 Pending Assignments

${pendingSection || '_No pending assignments! 🎉_'}

## 📚 By Course
${courseSections}

## ✅ Completed

${completedTasks.map(t => `- [x] **${t.title}** | ${t.courseName} | ${t.submissionState}${t.grade !== null ? ` | ${t.grade}/${t.maxPoints}pts` : ''}`).join('\n') || '_Nothing completed yet_'}

---
*Auto-generated by n8n Task Tracking workflow*
*Powered by Google Classroom API*
`;

return [{
  json: {
    markdownContent: markdown,
    stats: { total, complete, overdue, dueThisWeek },
    generatedAt: ts
  }
}];

// Check for urgent/overdue tasks and prepare notification payload
const data = $input.first().json;
const stats = data.stats;

const shouldNotify = stats.overdue > 0 || stats.dueThisWeek > 0;

if (!shouldNotify) {
  return [{ json: { notified: false, reason: 'No urgent tasks' } }];
}

let message = '📚 Study Automation - Task Alert\n\n';
if (stats.overdue > 0) message += `🔴 ${stats.overdue} overdue assignment(s)!\n`;
if (stats.dueThisWeek > 0) message += `🟡 ${stats.dueThisWeek} assignment(s) due this week\n`;
message += `\nCheck your Assignment Tracker in Obsidian.`;

return [{
  json: {
    notified: true,
    message: message,
    stats: stats
  }
}];
